// Filter to only active students whose email is due this week
const today = new Date();
today.setHours(0, 0, 0, 0);

const activeStudents = $input.all().filter(item => {
  const row = item.json;

  // Must be active
  if (row.status !== 'active') return false;

  // Must have a schedule
  if (!row.schedule_json) return false;

  // Check if next_email_date is today or past
  if (row.next_email_date) {
    const emailDate = new Date(row.next_email_date);
    emailDate.setHours(0, 0, 0, 0);
    if (emailDate > today) return false;
  }

  // Parse current week (default to 1 if not set)
  const currentWeek = parseInt(row.current_week) || 1;

  // Don't send past week 15
  if (currentWeek > 15) return false;

  return true;
});

if (activeStudents.length === 0) {
  // No students to email — graceful exit
  return [{ json: { skipped: true, reason: 'No active students due for email today', timestamp: new Date().toISOString() } }];
}

// Enrich each student item with parsed schedule
return activeStudents.map(item => {
  const row = item.json;
  let schedule = [];
  try {
    schedule = JSON.parse(row.schedule_json);
  } catch(e) {
    console.log('Failed to parse schedule for:', row.student_email);
  }

  const currentWeek = parseInt(row.current_week) || 1;
  const weekIndex = currentWeek - 1;
  const currentWeekData = schedule[weekIndex] || schedule[0];
  const nextWeekData = schedule[weekIndex + 1] || null;

  return {
    json: {
      ...row,
      current_week_num: currentWeek,
      current_week_data: currentWeekData,
      next_week_data: nextWeekData,
      schedule_parsed: schedule,
      total_weeks: schedule.length,
      percent_complete: Math.round((currentWeek / 15) * 100)
    }
  };
});

